report_script:
result = []

expense_filters = {}

if filters.get("driver"):
    expense_filters["driver"] = filters.get("driver")

if filters.get("from_date"):
    expense_filters["posting_date"] = [">=", filters.get("from_date")]

if filters.get("to_date"):

    if "posting_date" in expense_filters:
        expense_filters["posting_date"] = [
            "between",
            [
                filters.get("from_date"),
                filters.get("to_date")
            ]
        ]
    else:
        expense_filters["posting_date"] = ["<=", filters.get("to_date")]

expense_entries = frappe.get_all(
    "Driver Expense Entry",
    filters=expense_filters,
    fields=[
        "name",
        "posting_date",
        "trip",
        "driver",
        "driver_name",
        "advance_amount",
        "total_expense",
        "balance_amount"
    ]
)

for entry in expense_entries:

    # Advance Status

    if entry.balance_amount >= 0:
        advance_status = "Sufficient"
    else:
        advance_status = "Extra Payment Needed"

    # Highest Expense Category

    highest_expense = ""
    max_amount = 0

    expense_rows = frappe.get_all(
        "Driver Expense Detail",
        filters={
            "parent": entry.name
        },
        fields=[
            "expense_category",
            "amount"
        ]
    )

    for row in expense_rows:

        if row.amount > max_amount:

            max_amount = row.amount
            highest_expense = row.expense_category

    # Suspicious Flag

    if entry.total_expense > entry.advance_amount:
        suspicious = "Yes"
    else:
        suspicious = "No"

    result.append({
        "trip": entry.trip,
        "driver": entry.driver_name,
        "advance_amount": entry.advance_amount,
        "total_expense": entry.total_expense,
        "balance_amount": entry.balance_amount,
        "advance_status": advance_status,
        "highest_expense": highest_expense,
        "suspicious": suspicious
    })
